import{_ as e,o as a,c as t,ag as l}from"./chunks/framework-C5-Jzrz4.js";const o=JSON.parse('{"title":"常见排障","description":"登录、请求、字典、路由等高频问题排查路径","frontmatter":{"title":"常见排障","description":"登录、请求、字典、路由等高频问题排查路径"},"headers":[],"relativePath":"scripts/maintenance/常见排障.md","filePath":"scripts/maintenance/常见排障.md","lastUpdated":null}');const i=e({name:"scripts/maintenance/常见排障.md"},[["render",function(e,o,i,d,r,c){return a(),t("div",null,[...o[0]||(o[0]=[l('<h1 id="常见排障" tabindex="-1">常见排障 <a class="header-anchor" href="#常见排障" aria-label="Permalink to &quot;常见排障&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本页聚焦当前代码中最常见的故障点，并给出对应源码定位入口。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>登录与权限异常</li><li>接口请求异常</li><li>页面数据/字典异常</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/src/router/guard.ts</code></li><li><code>apps/web-antd/src/utils/http/index.ts</code></li><li><code>apps/web-antd/src/utils/http/helper.ts</code></li><li><code>apps/web-antd/src/store/{auth,dict,tenant,notify}.ts</code></li><li><code>apps/web-antd/src/utils/message.ts</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="登录后跳转异常" tabindex="-1">登录后跳转异常 <a class="header-anchor" href="#登录后跳转异常" aria-label="Permalink to &quot;登录后跳转异常&quot;">​</a></h3><p>优先检查：</p><ul><li><code>useAuthStore().authLogin</code> 是否成功设置 token</li><li><code>router/guard.ts</code> 中 <code>accessStore.isAccessChecked</code> 状态</li><li><code>generateAccess</code> 是否拉取到菜单并成功注册路由</li></ul><h3 id="_401-循环或重复登出" tabindex="-1">401 循环或重复登出 <a class="header-anchor" href="#_401-循环或重复登出" aria-label="Permalink to &quot;401 循环或重复登出&quot;">​</a></h3><p>优先检查：</p><ul><li><code>handleUnauthorizedLogout()</code> 的防重入逻辑</li><li>后端 <code>logout</code> 接口是否错误返回 401（源码对此有异常分支）</li></ul><h3 id="列表接口分页显示异常" tabindex="-1">列表接口分页显示异常 <a class="header-anchor" href="#列表接口分页显示异常" aria-label="Permalink to &quot;列表接口分页显示异常&quot;">​</a></h3><p>优先检查：</p><ul><li>后端是否返回 <code>rows + total</code></li><li>请求层 <code>onSuccess</code> 是否走到“无 data 字段返回 other”分支</li></ul><h3 id="字典重复请求或数据不刷新" tabindex="-1">字典重复请求或数据不刷新 <a class="header-anchor" href="#字典重复请求或数据不刷新" aria-label="Permalink to &quot;字典重复请求或数据不刷新&quot;">​</a></h3><p>优先检查：</p><ul><li><code>useDictStore</code> 的 <code>dictRequestCache</code> 与 <code>dictOptionsMap</code></li><li>切换用户/租户后是否触发 <code>dictStore.resetCache()</code></li></ul><h3 id="sse-websocket-无消息" tabindex="-1">SSE/WebSocket 无消息 <a class="header-anchor" href="#sse-websocket-无消息" aria-label="Permalink to &quot;SSE/WebSocket 无消息&quot;">​</a></h3><p>优先检查：</p><ul><li><code>VITE_GLOB_SSE_ENABLE</code> / <code>VITE_GLOB_WEBSOCKET_ENABLE</code></li><li><code>utils/message.ts</code> 中连接地址拼装</li><li>代理层是否透传升级头与关闭缓冲</li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>建议先查浏览器 Network 与 Console，再进入源码定位。</li><li>同类错误优先修复统一封装层（HTTP、router guard、store），避免页面级重复补丁。</li><li>文档中未覆盖的异常场景，按“入口层 -&gt; 共享层 -&gt; 页面层”顺序追踪。</li></ul>',25)])])}]]);export{o as __pageData,i as default};
